import{_ as t,c as a,S as i,o as s}from"./chunks/framework.BjmDYXuv.js";const u=JSON.parse('{"title":"Simulation Form","description":"","frontmatter":{},"headers":[],"relativePath":"spaces/simulation-form.md","filePath":"spaces/simulation-form.md","lastUpdated":1775813604000}'),o={name:"spaces/simulation-form.md"};function l(n,e,r,c,h,d){return s(),a("div",null,e[0]||(e[0]=[i(`<h1 id="simulation-form" tabindex="-1">Simulation Form <a class="header-anchor" href="#simulation-form" aria-label="Permalink to &quot;Simulation Form&quot;">​</a></h1><p><strong>Live:</strong> <a href="https://huggingface.co/spaces/CERN/colliderml-simulation" target="_blank" rel="noreferrer">huggingface.co/spaces/CERN/colliderml-simulation</a><strong>Source:</strong> <a href="https://github.com/OpenDataDetector/ColliderML/tree/main/spaces/simulation-form" target="_blank" rel="noreferrer"><code>spaces/simulation-form/</code></a></p><p>A graphical front door for the SaaS simulation backend. Two tabs:</p><ol><li><strong>Simulate</strong> — a form with dropdowns for channel, events, and pileup. Submit, get a request ID, then hit <strong>Refresh status</strong> to poll until the job completes.</li><li><strong>Chat</strong> — a natural-language interface backed by Claude that can estimate compute costs, check your credit balance, and submit jobs on your behalf after you confirm.</li></ol><p>Both tabs talk to the same backend that the <a href="./../library/simulate.html"><code>colliderml.simulate(remote=True)</code></a> Python API uses. Whichever entry point you pick, you end up in the same queue.</p><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>Authentication is HuggingFace OAuth. Click <strong>Sign in with HuggingFace</strong> and the Space receives a scoped token that it forwards as a bearer credential to the backend. The backend verifies the token, checks quotas, and charges your credit balance.</p><p>Every user starts with 10 credits on first sign-in. See <a href="./../guide/remote-simulation.html#credits">Remote Simulation</a> for the credit economics.</p><h2 id="the-form-tab" tabindex="-1">The form tab <a class="header-anchor" href="#the-form-tab" aria-label="Permalink to &quot;The form tab&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Field</th><th style="text-align:left;">Meaning</th></tr></thead><tbody><tr><td style="text-align:left;">Physics channel</td><td style="text-align:left;"><code>ttbar</code>, <code>higgs_portal</code>, <code>zmumu</code>, <code>zee</code>, <code>diphoton</code>, <code>jets</code>, <code>susy_gmsb</code>, <code>hidden_valley</code>, <code>zprime</code>, <code>single_muon</code></td></tr><tr><td style="text-align:left;">Events</td><td style="text-align:left;">Number of events to simulate (1–100 000)</td></tr><tr><td style="text-align:left;">Pileup</td><td style="text-align:left;">Pileup level in steps of 10, up to 200 (HL-LHC)</td></tr><tr><td style="text-align:left;">Seed</td><td style="text-align:left;">Random seed forwarded to every stage (default 42)</td></tr></tbody></table><p>After submission the UI shows:</p><ul><li>the backend&#39;s assigned request ID,</li><li>an estimated cost in credits,</li><li>an estimated wall-clock completion time,</li><li>a note if the request was deduplicated against an existing run (zero credits in that case).</li></ul><h2 id="the-chat-tab" tabindex="-1">The chat tab <a class="header-anchor" href="#the-chat-tab" aria-label="Permalink to &quot;The chat tab&quot;">​</a></h2><p>The chat agent is Claude (<code>claude-sonnet-4-6</code>) with three tools:</p><ul><li><code>check_balance</code> — queries <code>/v1/me</code> and reports credits remaining.</li><li><code>estimate_compute</code> — dry-runs the backend&#39;s capacity estimate and returns credits + estimated minutes.</li><li><code>submit_simulation</code> — posts to <code>/v1/simulate</code>. The system prompt requires the agent to confirm cost + parameters with the user before calling this tool.</li></ul><p>The chat tab only works if the Space has <code>ANTHROPIC_API_KEY</code> set as a Space-level secret. Without it the chat tab shows a &quot;not configured&quot; message but the rest of the Space still works.</p><h2 id="required-space-secrets" tabindex="-1">Required Space secrets <a class="header-anchor" href="#required-space-secrets" aria-label="Permalink to &quot;Required Space secrets&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Secret</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>COLLIDERML_BACKEND</code></td><td style="text-align:left;">Backend URL; defaults to <code>https://api.colliderml.com</code></td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_API_KEY</code></td><td style="text-align:left;">Needed for the Chat tab; without it the tab degrades gracefully</td></tr></tbody></table><p>See the <a href="./../internal/deployment.html#space-secrets">sync-spaces workflow docs</a> for how to set these after the first automated sync.</p><h2 id="running-it-locally" tabindex="-1">Running it locally <a class="header-anchor" href="#running-it-locally" aria-label="Permalink to &quot;Running it locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spaces/simulation-form</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install -r requirements.txt</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> COLLIDERML_BACKEND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:8000   # point at your local backend</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sk-ant-...               # optional, only for the Chat tab</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.py</span></span></code></pre></div><p>Use a HuggingFace token instead of OAuth for local testing — see the <code>fetch_me</code> call in <code>app.py</code> for where to inject one.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../guide/remote-simulation.html">Remote Simulation guide</a> — the CLI equivalent of this Space</li><li><a href="./../library/simulate.html"><code>colliderml.simulate</code></a> — the Python API it mirrors</li><li><a href="./../library/remote.html"><code>colliderml.remote</code></a> — the client library the backend speaks to</li></ul>`,24)]))}const m=t(o,[["render",l]]);export{u as __pageData,m as default};
